export type RuntimeEvent = { "kind": "operation_accepted", operation_id: RuntimeOperationId, } | { "kind": "operation_terminal", operation_id: RuntimeOperationId, terminal: RuntimeOperationTerminal, } | { "kind": "binding_established", binding_id: RuntimeBindingId, } | { "kind": "binding_lost", binding_id: RuntimeBindingId, reason: string, } | { "kind": "binding_reestablished", recovery_intent_id: RuntimeRecoveryIntentId, binding_epoch: BindingEpoch, old_binding_id: RuntimeBindingId, old_driver_generation: RuntimeDriverGeneration, new_binding_id: RuntimeBindingId, new_driver_generation: RuntimeDriverGeneration, source_thread_id: DriverThreadId, profile_digest: ProfileDigest, bound_profile: RuntimeProfile, } | { "kind": "protocol_violation", code: RuntimeProtocolViolationCode, message: string, critical: boolean, } | { "kind": "thread_status_changed", status: RuntimeThreadStatus, } | { "kind": "turn_started", turn_id: RuntimeTurnId, } | { "kind": "turn_terminal", turn_id: RuntimeTurnId, terminal: RuntimeTurnTerminal, message: string | null, } | { "kind": "item_started", turn_id: RuntimeTurnId, item_id: RuntimeItemId, initial_content: RuntimeItemContent, } | { "kind": "conversation_delta", turn_id: RuntimeTurnId, item_id: RuntimeItemId, delta: RuntimeConversationDelta, } | { "kind": "token_usage_updated", turn_id: RuntimeTurnId, usage: RuntimeTokenUsage, } | { "kind": "conversation_error", turn_id: RuntimeTurnId | null, error: RuntimeConversationError, } | { "kind": "provider_status", turn_id: RuntimeTurnId, status: RuntimeProviderStatus, } | { "kind": "item_terminal", turn_id: RuntimeTurnId, item_id: RuntimeItemId, terminal: RuntimeItemTerminal, } | { "kind": "interaction_requested", turn_id: RuntimeTurnId, item_id: RuntimeItemId | null, interaction_id: RuntimeInteractionId, request: RuntimeInteractionRequest, } | { "kind": "interaction_terminal", turn_id: RuntimeTurnId, interaction_id: RuntimeInteractionId, terminal: RuntimeInteractionTerminal, } | { "kind": "context_checkpoint_prepared", checkpoint_id: ContextCheckpointId, candidate_id: ContextCandidateId, compaction_id: ContextCompactionId, } | { "kind": "context_activation_applied", activation_id: ContextActivationId, candidate_id: ContextCandidateId, digest: ContextDigest, driver_context_revision: DriverContextRevision, } | { "kind": "context_compaction_terminal", compaction_id: ContextCompactionId, operation_id: RuntimeOperationId, terminal: RuntimeOperationTerminal, context_revision: ContextRevision, } | { "kind": "context_checkpoint_activated", checkpoint_id: ContextCheckpointId, candidate_id: ContextCandidateId, activation_id: ContextActivationId, compaction_id: ContextCompactionId, context_revision: ContextRevision, digest: ContextDigest, } | { "kind": "driver_context_compacted_opaque" } | { "kind": "hook_run_accepted", hook_run_id: HookRunId, definition_id: HookDefinitionId, point: HookPoint, plan_revision: HookPlanRevision, plan_digest: HookPlanDigest, operation_id: RuntimeOperationId | null, turn_id: RuntimeTurnId | null, item_id: RuntimeItemId | null, interaction_id: RuntimeInteractionId | null, } | { "kind": "hook_run_started", hook_run_id: HookRunId, } | { "kind": "hook_run_terminal", hook_run_id: HookRunId, terminal: HookRunTerminal, decision: HookRunDecision, message: string | null, effect_ids: Array<HookEffectId>, } | { "kind": "hook_plan_bound", plan_revision: HookPlanRevision, plan_digest: HookPlanDigest, };

export type RuntimeEventEnvelope = { thread_id: RuntimeThreadId,
/**
 * Authoritative producer timestamp used by presentation projections.
 */
occurred_at_ms: bigint, sequence: EventSequence | null,
/**
 * Present only for live, non-durable events. Together these coordinates form a stable
 * reconnect cursor inside one binding generation; they are never persisted as journal facts.
 */
transient: RuntimeTransientCoordinate | null, revision: RuntimeRevision, event: RuntimeEvent, };

export type RuntimeEventSubscription = { thread_id: RuntimeThreadId, after: EventSequence | null, include_transient: boolean,
/**
 * Optional cursor for bounded replay of the currently active live stream.
 */
transient_after: RuntimeTransientSequence | null,
/**
 * Rejects replay from an obsolete binding generation after reconnect or target switch.
 */
stream_generation: RuntimeDriverGeneration | null, };

export type RuntimeExecuteError = { "kind": "unsupported", command: RuntimeCommandKind, reason: string, } | { "kind": "unavailable", reason: string, retryable: boolean, } | { "kind": "revision_conflict", expected: RuntimeRevision, actual: RuntimeRevision, } | { "kind": "operation_conflict", existing_operation_id: RuntimeOperationId, conflict: OperationConflictKind, } | { "kind": "context_compaction_in_progress", operation_id: RuntimeOperationId, } | { "kind": "invalid_command", reason: string, } | { "kind": "incompatible", reason: string, } | { "kind": "persistence", reason: string, retryable: boolean, };

export type RuntimeInput = { "kind": "text", text: string, } | { "kind": "image", mime_type: string, data_url: string, } | { "kind": "file_reference", uri: string, media_type: string | null, } | { "kind": "structured", schema: string, value: JsonValue, };

export type RuntimeInteractionId = string;

export type RuntimeInteractionKind = "command_approval" | "file_change_approval" | "permission_approval" | "user_input_request" | "mcp_elicitation" | "dynamic_tool_execution";

export type RuntimeInteractionRequest = { "kind": "command_approval", params: CommandExecutionRequestApprovalParams, } | { "kind": "file_change_approval", params: FileChangeRequestApprovalParams, } | { "kind": "permission_approval", params: PermissionsRequestApprovalParams, } | { "kind": "user_input_request", params: ToolRequestUserInputParams, } | { "kind": "mcp_elicitation", params: McpServerElicitationRequestParams, } | { "kind": "dynamic_tool_execution", params: DynamicToolCallParams, };

export type RuntimeInteractionTerminal = "resolved" | "expired" | "cancelled" | "failed" | "lost";

export type RuntimeItemContent = AgentDashThreadItem;

export type RuntimeItemId = string;

export type RuntimeItemTerminal = { "kind": "completed", final_content: RuntimeItemContent, } | { "kind": "failed", message: string | null, } | { "kind": "cancelled", message: string | null, } | { "kind": "lost", message: string | null, };

export type RuntimeOperationId = string;

export type RuntimeOperationTerminal = { "kind": "succeeded" } | { "kind": "failed", retryable: boolean, message: string | null, } | { "kind": "lost", retryable: boolean, message: string | null, };

export type RuntimeOperationView = { operation_id: RuntimeOperationId, idempotency_key: IdempotencyKey, actor: RuntimeActor, command: RuntimeCommand, receipt: OperationReceipt, terminal: RuntimeOperationTerminal | null, };

export type RuntimeProfile = { reference_class: ReferenceRuntimeClass, input: InputProfile, instruction: InstructionProfile, tools: ToolProfile, workspace: WorkspaceProfile, interactions: InteractionProfile, lifecycle: Array<LifecycleCapability>, hooks: HookProfile, context: ContextProfile, telemetry_config: Array<TelemetryCapability>, };

export type RuntimeProtocolViolationCode = "driver_operation_acceptance" | "driver_runtime_owned_context_event" | "driver_runtime_owned_hook_event" | "driver_runtime_owned_binding_event" | "invalid_lifecycle_transition" | "duplicate_terminal";

export type RuntimeProviderPhase = "connecting" | "connected_waiting_first_delta" | "streaming" | "retry_scheduled" | "retrying" | "failed" | "succeeded";

export type RuntimeProviderStatus = { phase: RuntimeProviderPhase, attempt: number, max_attempts: number, will_retry: boolean, delay_ms: bigint | null, reason_code: string | null, message: string | null, provider: string | null, model: string | null, };

export type RuntimeRecoveryIntentId = string;

export type RuntimeRevision = bigint;

export type RuntimeServiceInstanceId = string;

export type RuntimeSnapshot = { thread_id: RuntimeThreadId, revision: RuntimeRevision,
/**
 * Durable journal cursor atomically represented by this snapshot.
 */
latest_event_sequence: EventSequence,
/**
 * Authoritative time at which this presentation baseline was materialized.
 */
captured_at_ms: bigint, status: RuntimeThreadStatus, active_turn_id: RuntimeTurnId | null, binding_id: RuntimeBindingId, binding_epoch: BindingEpoch, profile_digest: ProfileDigest, bound_profile: RuntimeProfile, active_checkpoint_id: ContextCheckpointId | null, context_revision: ContextRevision, settings_revision: ThreadSettingsRevision, tool_set_revision: ToolSetRevision, pending_interactions: Array<RuntimeInteractionId>, command_availability: { [key in RuntimeCommandKind]?: CommandAvailability }, transcript: Array<RuntimeTranscriptItem>, transcript_fidelity: ContextFidelity, };

export type RuntimeSnapshotError = { "kind": "not_found" } | { "kind": "revision_unavailable", requested: RuntimeRevision, current: RuntimeRevision, } | { "kind": "context_revision_unavailable", requested: ContextRevision, current: ContextRevision, } | { "kind": "inconsistent_context", code: ContextSnapshotConsistencyCode, } | { "kind": "unavailable", reason: string, };

export type RuntimeSnapshotQuery = { "kind": "operation", operation_id: RuntimeOperationId, } | { "kind": "thread", thread_id: RuntimeThreadId, at_revision: RuntimeRevision | null, } | { "kind": "context", thread_id: RuntimeThreadId, at_context_revision: ContextRevision | null, };

export type RuntimeSnapshotResult = { "kind": "operation", operation: RuntimeOperationView, } | { "kind": "thread", snapshot: RuntimeSnapshot, } | { "kind": "context", context: RuntimeContextView, };

export type RuntimeSubscribeError = { "kind": "not_found" } | { "kind": "invalid_cursor" } | { "kind": "cursor_gap", requested: EventSequence, earliest_available: EventSequence, latest_available: EventSequence, } | { "kind": "unavailable", reason: string, retryable: boolean, };

export type RuntimeThreadId = string;

export type RuntimeThreadStatus = "active" | "suspended" | "desynchronized" | "closed" | "lost";

export type RuntimeTokenUsage = { input_tokens: bigint, cached_input_tokens: bigint, output_tokens: bigint, reasoning_output_tokens: bigint, total_tokens: bigint, };

export type RuntimeTranscriptItem = { turn_id: RuntimeTurnId, item_id: RuntimeItemId, final_content: RuntimeItemContent, };

export type RuntimeTransientCoordinate = { binding_id: RuntimeBindingId, stream_generation: RuntimeDriverGeneration, sequence: RuntimeTransientSequence, event_id: RuntimeTransientEventId, turn_id: RuntimeTurnId | null, };

export type RuntimeTransientEventId = string;

export type RuntimeTransientSequence = bigint;

export type RuntimeTurnId = string;

export type RuntimeTurnTerminal = "completed" | "interrupted" | "refused" | "limit_reached" | "failed" | "lost";

export type SemanticStrength = "observed_only" | "boundary_adapted" | "exact_durable_boundary" | "exact_synchronous";

export type ShellExecExecutionMode = "platform" | "mountExec";

export type SurfaceDigest = string;

export type SurfaceRevision = bigint;

export type TelemetryCapability = "usage" | "reasoning" | "deltas" | "diagnostics" | "configuration_evidence";

export type ThreadSettingsRevision = bigint;

export type ToolChannel = "direct_callback" | "mcp_facade" | "driver_native";

export type ToolProfile = { channels: Array<ToolChannel>, configuration_boundary: ConfigurationBoundary, cancellation: boolean, };

export type ToolProtocolProjection = { "family": "command" } | { "family": "file_change" } | { "family": "fs_read" } | { "family": "fs_grep" } | { "family": "fs_glob" } | { "family": "mcp", server_key: string, } | { "family": "dynamic", namespace: string | null, } | { "family": "vfs", operation: string, } | { "family": "runtime_action", action_key: string, } | { "family": "workspace_module", operation: string, } | { "family": "companion", operation: string, } | { "family": "task", operation: string, } | { "family": "wait" } | { "family": "lifecycle_complete" };

export type ToolSetRevision = bigint;

export type WorkspaceCapability = "read" | "write" | "search" | "multiple_roots" | "virtual_file_system";

export type WorkspaceProfile = { capabilities: Array<WorkspaceCapability>, mechanism: DeliveryMechanism, };
